import { useState, useCallback, useRef } from "react";
import { Restaurant } from "./useRestaurants";

const SEARCH_URL = `${import.meta.env.VITE_SUPABASE_URL}/functions/v1/ai-search-restaurants`;

export interface AISearchResult {
  restaurants: Restaurant[];
  message: string;
  landmark?: { name: string; lat: number; lng: number } | null;
}

export const useAISearchRestaurants = () => {
  const [isSearching, setIsSearching] = useState(false);
  const [aiResults, setAiResults] = useState<AISearchResult | null>(null);
  const [aiError, setAiError] = useState<string | null>(null);
  const abortRef = useRef<AbortController | null>(null);

  const search = useCallback(async (query: string, userLat?: number | null, userLng?: number | null, activeTab?: string) => {
    if (!query.trim()) {
      setAiResults(null);
      setAiError(null);
      return;
    }

    abortRef.current?.abort();
    abortRef.current = new AbortController();

    setIsSearching(true);
    setAiError(null);

    try {
      const resp = await fetch(SEARCH_URL, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          Authorization: `Bearer ${import.meta.env.VITE_SUPABASE_PUBLISHABLE_KEY}`,
        },
        body: JSON.stringify({ query: query.trim(), userLat, userLng, activeTab: activeTab || null }),
        signal: abortRef.current.signal,
      });

      if (!resp.ok) {
        const errData = await resp.json().catch(() => ({}));
        throw new Error(errData.error || `Search failed (${resp.status})`);
      }

      const data = await resp.json();

      setAiResults({
        restaurants: (data?.restaurants || []).map((r: any) => ({
          ...r,
          distance: r.distance_km,
        })),
        message: data?.message || '',
        landmark: data?.landmark || null,
      });
    } catch (err: any) {
      if (err?.name === 'AbortError') return;
      console.error('AI search error:', err);
      setAiError(err?.message || 'Search failed');
      setAiResults(null);
    } finally {
      setIsSearching(false);
    }
  }, []);

  const clearResults = useCallback(() => {
    setAiResults(null);
    setAiError(null);
  }, []);

  return { search, isSearching, aiResults, aiError, clearResults };
};
